  lat: el.lat || el.center?.lat || s.lat,
  lng: el.lon || el.center?.lon || s.lng,
  website: el.tags?.website || el.tags?.url || '',
  phone: el.tags?.phone || el.tags?.['contact:phone'] || ''
} }));

