      lead.ai_needs_marketing? 'marketing'    : ''
    ].filter(Boolean).join(', ')
  ].join('. ');
  return {
    json: {
      ...lead,
      _embedding: embedding,
      _text_chunk: textChunk,
      _embed_failed: false
    }
